-- ==================== ESTADIOS (3) ====================
INSERT INTO places (name, slug, description, short_description, category, subcategory, city, neighborhood, address, latitude, longitude, price_level, rating, rating_count, image_url, tags, mundial_relevant, mundial_info) VALUES
('Estadio Azteca', 'estadio-azteca', 'El legendario Coloso de Santa Ursula, unico estadio en albergar dos finales de Copa del Mundo (1970, 1986). Con capacidad para 87,523 espectadores, es el estadio mas grande de Mexico y uno de los mas iconicos del mundo. Sede de partidos del Mundial 2026.', 'Estadio legendario sede del Mundial 2026', 'estadio', 'mundial', 'CDMX', 'Estadio Azteca', 'Calz. de Tlalpan 3465, Sta. Ursula Coapa', 19.3029, -99.1505, 3, 4.7, 15420, 'https://images.unsplash.com/photo-1577223625816-7546f13df25d?w=800&q=80', ARRAY['mundial', 'futbol', 'estadio', 'iconico', 'historia'], true, '{"capacity": 87523, "matches": "Fase de grupos y octavos de final", "transport": "Tren Ligero Estadio Azteca, Metrobus Estadio", "tips": "Llegar 3 horas antes, no mochilas grandes"}'),

('Estadio Akron', 'estadio-akron', 'Hogar de las Chivas de Guadalajara, este moderno estadio con capacidad para 49,850 espectadores cuenta con arquitectura volcanica unica. Sede del Mundial 2026, ofrecera una experiencia de futbol autentica en el corazon de Jalisco.', 'Estadio moderno de Chivas sede del Mundial', 'estadio', 'mundial', 'GDL', 'Estadio Akron', 'Av. Circuito JVC 2800, El Bajio', 20.6810, -103.4630, 3, 4.6, 8930, 'https://images.unsplash.com/photo-1522778119026-d647f0596c20?w=800&q=80', ARRAY['mundial', 'futbol', 'estadio', 'moderno', 'chivas'], true, '{"capacity": 49850, "matches": "Fase de grupos", "transport": "Shuttle desde Centro GDL, Mi Macro Periferico", "tips": "Estacionamiento limitado, usa transporte publico"}'),

('Estadio BBVA', 'estadio-bbva', 'El estadio mas moderno de Mexico, hogar de Rayados de Monterrey. Con capacidad para 53,500 espectadores y tecnologia de punta, sera una de las sedes mas impresionantes del Mundial 2026. Vista espectacular al Cerro de la Silla.', 'Estadio de alta tecnologia sede del Mundial', 'estadio', 'mundial', 'MTY', 'Estadio BBVA', 'Av. Pablo Livas 2011, La Pastora', 25.6698, -100.2437, 3, 4.8, 11200, 'https://images.unsplash.com/photo-1556056333-18d1f498a363?w=800&q=80', ARRAY['mundial', 'futbol', 'estadio', 'tecnologia', 'rayados'], true, '{"capacity": 53500, "matches": "Fase de grupos y octavos de final", "transport": "Metrorrey linea especial, shuttle desde centro", "tips": "Vistas al Cerro de la Silla desde las gradas superiores"}');

