INSERT INTO places (name, slug, description, short_description, category, subcategory, city, neighborhood, address, latitude, longitude, price_level, rating, rating_count, image_url, tags, mundial_relevant, mundial_info) VALUES
('Fan Zone Chapultepec', 'fan-zone-chapultepec', 'La fan zone principal de CDMX ubicada en el Bosque de Chapultepec. Pantallas gigantes, actividades interactivas, comida de todo Mexico y conciertos en vivo. Capacidad para 25,000 aficionados.', 'Fan zone principal de CDMX en Chapultepec', 'fan_zone', 'oficial', 'CDMX', 'Chapultepec', 'Bosque de Chapultepec 1a Seccion', 19.4212, -99.1859, 1, 4.5, 3200, 'https://images.unsplash.com/photo-1459865264687-595d652de67e?w=800&q=80', ARRAY['mundial', 'fan_zone', 'pantalla_gigante', 'gratis', 'familia'], true, '{"capacity": 25000, "schedule": "Dias de partido 8am-11pm", "amenities": "Pantallas 4K, food trucks, zona VIP"}'),

('Fan Zone Zocalo', 'fan-zone-zocalo', 'Fan zone en la plaza mas grande de Latinoamerica. Pantalla gigante frente a Palacio Nacional, ambiente festivo y cocina tradicional mexicana.', 'Fan zone historica en el Zocalo de CDMX', 'fan_zone', 'oficial', 'CDMX', 'Centro Historico', 'Plaza de la Constitucion, Centro', 19.4326, -99.1332, 1, 4.3, 2800, 'https://images.unsplash.com/photo-1518105779142-d975f22f1b0a?w=800&q=80', ARRAY['mundial', 'fan_zone', 'historico', 'gratis', 'cultura'], true, '{"capacity": 50000, "schedule": "Dias de partido", "amenities": "Pantallas LED, escenario musical"}'),

('Fan Zone Reforma', 'fan-zone-reforma', 'Punto de encuentro sobre Paseo de la Reforma con vista al Angel de la Independencia. Ideal para celebrar goles con miles de aficionados.', 'Fan zone en el corazon de Reforma', 'fan_zone', 'oficial', 'CDMX', 'Reforma', 'Paseo de la Reforma, Glorieta del Angel', 19.4270, -99.1677, 1, 4.4, 1900, 'https://images.unsplash.com/photo-1543326727-cf6c39e8f84c?w=800&q=80', ARRAY['mundial', 'fan_zone', 'angel', 'celebracion', 'gratis'], true, '{"capacity": 15000}'),

('Fan Zone Condesa', 'fan-zone-condesa', 'Fan zone urbana en Parque Mexico con bares y restaurantes alrededor. Ambiente cosmopolita y opciones gastronomicas premium.', 'Fan zone bohemia en la Condesa', 'fan_zone', 'informal', 'CDMX', 'Condesa', 'Parque Mexico, Condesa', 19.4121, -99.1738, 2, 4.6, 1500, 'https://images.unsplash.com/photo-1574629810360-7efbbe195018?w=800&q=80', ARRAY['mundial', 'fan_zone', 'bohemio', 'gastronomia', 'bar'], true, '{"type": "informal", "nearby_bars": 20}'),

('Fan Fest Guadalajara', 'fan-fest-guadalajara', 'Fan zone principal de Guadalajara en la explanada de la Minerva. Pantallas, musica en vivo y la mejor birria de Jalisco.', 'Fan zone principal de Guadalajara', 'fan_zone', 'oficial', 'GDL', 'Chapultepec GDL', 'Glorieta Minerva, Av. Vallarta', 20.6740, -103.3980, 1, 4.4, 2100, 'https://images.unsplash.com/photo-1606925797300-0b35e9d1794e?w=800&q=80', ARRAY['mundial', 'fan_zone', 'minerva', 'birria', 'tequila'], true, '{"capacity": 20000}'),

('Fan Zone Tlaquepaque', 'fan-zone-tlaquepaque', 'Fan zone con sabor mexicano en el Pueblo Magico. Mariachi en vivo, artesanias y tequila entre cada gol.', 'Fan zone en Pueblo Magico de Tlaquepaque', 'fan_zone', 'informal', 'GDL', 'Tlaquepaque', 'Jardin Hidalgo, Tlaquepaque', 20.6400, -103.3100, 1, 4.5, 1200, 'https://images.unsplash.com/photo-1489599849927-2ee91cede3ba?w=800&q=80', ARRAY['mundial', 'fan_zone', 'pueblo_magico', 'mariachi', 'artesanias'], true, '{"type": "informal"}'),

('Fan Zone Centro GDL', 'fan-zone-centro-gdl', 'Pantalla gigante en Plaza Liberacion frente a la Catedral. Ambiente familiar con gastronomia jalisciense.', 'Fan zone en el centro de Guadalajara', 'fan_zone', 'oficial', 'GDL', 'Centro Historico GDL', 'Plaza Liberacion, Centro', 20.6772, -103.3477, 1, 4.3, 1800, 'https://images.unsplash.com/photo-1431324155629-1a6deb1dec8d?w=800&q=80', ARRAY['mundial', 'fan_zone', 'catedral', 'gratis'], true, '{"capacity": 15000}'),

('Fan Zone Macroplaza MTY', 'fan-zone-macroplaza-mty', 'La fan zone mas grande de Monterrey en la Macroplaza. Con el Cerro de la Silla de fondo, pantallas gigantes y carne asada regiomontana.', 'Fan zone principal de Monterrey', 'fan_zone', 'oficial', 'MTY', 'Centro MTY', 'Macroplaza, Centro de Monterrey', 25.6714, -100.3094, 1, 4.5, 2500, 'https://images.unsplash.com/photo-1522778526097-ce0a22ceb253?w=800&q=80', ARRAY['mundial', 'fan_zone', 'macroplaza', 'carne_asada', 'cerveza'], true, '{"capacity": 30000}'),

('Fan Zone Fundidora', 'fan-zone-fundidora', 'Fan zone en el Parque Fundidora con areas verdes, pantallas y zona de food trucks. Ambiente industrial renovado perfecto para el futbol.', 'Fan zone en Parque Fundidora', 'fan_zone', 'oficial', 'MTY', 'Fundidora', 'Parque Fundidora, Monterrey', 25.6780, -100.2840, 1, 4.4, 1600, 'https://images.unsplash.com/photo-1508098682722-e99c43a406b2?w=800&q=80', ARRAY['mundial', 'fan_zone', 'fundidora', 'parque', 'industrial'], true, '{"capacity": 15000}'),

('Fan Zone Barrio Antiguo', 'fan-zone-barrio-antiguo', 'Fan zone informal en los bares del Barrio Antiguo. Cerveza artesanal, musica y futbol en cada esquina.', 'Fan zone bohemia en Barrio Antiguo', 'fan_zone', 'informal', 'MTY', 'Barrio Antiguo', 'Barrio Antiguo, Monterrey', 25.6700, -100.3080, 2, 4.3, 900, 'https://images.unsplash.com/photo-1567593810070-7a3d471af022?w=800&q=80', ARRAY['mundial', 'fan_zone', 'bar', 'cerveza_artesanal', 'bohemio'], true, '{"type": "informal"}'),

('Fan Zone San Pedro', 'fan-zone-san-pedro', 'Fan zone premium en zona exclusiva. Restaurantes con pantallas, terraza y servicio VIP para ver los partidos.', 'Fan zone premium en San Pedro', 'fan_zone', 'informal', 'MTY', 'San Pedro', 'Calzada del Valle, San Pedro', 25.6580, -100.3520, 3, 4.6, 800, 'https://images.unsplash.com/photo-1517457373958-b7bdd4587205?w=800&q=80', ARRAY['mundial', 'fan_zone', 'premium', 'terraza', 'vip'], true, '{"type": "informal_premium"}'),

('Fan Zone Roma', 'fan-zone-roma', 'Bares y restaurantes de la Roma Norte transmitiendo todos los partidos. Cocteleria de autor y tacos gourmet entre goles.', 'Fan zone informal en Roma Norte', 'fan_zone', 'informal', 'CDMX', 'Roma Norte', 'Av. Alvaro Obregon, Roma Norte', 19.4164, -99.1610, 2, 4.5, 1100, 'https://images.unsplash.com/photo-1560932684-5e552e2894e9?w=800&q=80', ARRAY['mundial', 'fan_zone', 'bar', 'cocteleria', 'tacos'], true, '{"type": "informal"}');

